@Service
class MatchingCacheService(
    private val redisTemplate: RedisTemplate<String, Any>
) {
    companion object {
        // 캐시 키 상수
        const val KEY_WAITING_QUEUE   = "matching:queue:waiting"      // Sorted Set
        const val KEY_USER_PROFILE    = "matching:profile:"           // Hash, TTL 5분
        const val KEY_BLOCKED_USERS   = "matching:blocked:"           // Set, TTL 10분
        const val KEY_RECENT_MATCHED  = "matching:recent:"            // Set, TTL 1시간
    }

    // 대기열: Redis Sorted Set (score = 대기 시작 시각 Unix timestamp)
    fun addToWaitingQueue(userId: String, waitingSince: Long) {
        redisTemplate.opsForZSet()
            .add(KEY_WAITING_QUEUE, userId, waitingSince.toDouble())
        // 만료 보호: 최대 10분 대기 허용
        redisTemplate.expire(KEY_WAITING_QUEUE, 10, TimeUnit.MINUTES)
    }

    fun getWaitingCandidates(excludeUserId: String, limit: Long = 20): Set<String>? {
        val all = redisTemplate.opsForZSet()
            .range(KEY_WAITING_QUEUE, 0, limit) ?: return null
        return all.filter { it != excludeUserId }.toSet()
    }

    fun removeFromWaitingQueue(userId: String) {
        redisTemplate.opsForZSet().remove(KEY_WAITING_QUEUE, userId)
    }

    // 프로필 캐시: TTL 5분 (자주 변경되지 않는 정보)
    fun cacheUserProfile(userId: String, profile: UserMatchProfileDto) {
        val key = "$KEY_USER_PROFILE$userId"
        redisTemplate.opsForHash<String, Any>().putAll(
            key,
            mapOf(
                "nickname"  to profile.nickname,
                "ageGroup"  to profile.ageGroup.toString(),
                "gender"    to profile.gender.toString(),
                "isActive"  to profile.isActive.toString()
            )
        )
        redisTemplate.expire(key, 5, TimeUnit.MINUTES)
    }

    fun getUserProfile(userId: String): UserMatchProfileDto? {
        val key = "$KEY_USER_PROFILE$userId"
        val entries = redisTemplate.opsForHash<String, String>().entries(key)
        if (entries.isEmpty()) return null
        return UserMatchProfileDto(
            nickname  = entries["nickname"] ?: return null,
            ageGroup  = entries["ageGroup"]?.toInt() ?: return null,
            gender    = entries["gender"]?.toInt() ?: return null,
            isActive  = entries["isActive"]?.toBoolean() ?: return null
        )
    }

    // 차단 목록 캐시: TTL 10분
    fun cacheBlockedUsers(userId: String, blockedIds: Set<String>) {
        val key = "$KEY_BLOCKED_USERS$userId"
        if (blockedIds.isNotEmpty()) {
            redisTemplate.opsForSet().add(key, *blockedIds.toTypedArray())
        }
        redisTemplate.expire(key, 10, TimeUnit.MINUTES)
    }

    fun getBlockedUsers(userId: String): Set<String>? {
        val key = "$KEY_BLOCKED_USERS$userId"
        if (!redisTemplate.hasKey(key)) return null
        return redisTemplate.opsForSet().members(key)?.map { it as String }?.toSet()
    }

    // 최근 통화 이력 캐시: TTL 1시간 (재매칭 방지)
    fun addRecentMatchedUser(userId: String, matchedUserId: String) {
        val key = "$KEY_RECENT_MATCHED$userId"
        redisTemplate.opsForSet().add(key, matchedUserId)
        redisTemplate.expire(key, 1, TimeUnit.HOURS)
    }

    fun getRecentMatchedUsers(userId: String): Set<String> {
        val key = "$KEY_RECENT_MATCHED$userId"
        return redisTemplate.opsForSet().members(key)
            ?.map { it as String }?.toSet() ?: emptySet()
    }
}
