## 3. 매칭 서비스 통합 최적화

**Before (느린 흐름)**

```kotlin
// 현재 추정 흐름: DB 다중 조회, 캐시 없음
fun matchUser(userId: String): MatchResult {
    // 1. 대기열 DB 조회 (전체 스캔 위험)
    val queue = callQueueRepository.findByStatus(0)

    // 2. 각 사용자 프로필 개별 DB 조회 (N+1)
    val candidates = queue.map { entry ->
        val profile = profileRepository.findByUserId(entry.userId)  // N회
        val blocked = blockRepository.findByUserId(userId)           // N회
        // ...필터링
    }

    // 3. 결과 반환
    return candidates.firstOrNull()?.let { MatchResult(it) }
        ?: MatchResult(status = "WAITING")
}
```

**After (캐시 + 최적화 쿼리 통합)**

```kotlin
// application/src/main/kotlin/com/maum/backend/service/call/MatchingService.kt
@Service
class MatchingService(
    private val callQueueRepository: CallQueueRepository,
    private val matchingCacheService: MatchingCacheService,
    private val userProfileRepository: UserProfileRepository
) {
    @Transactional
    fun matchUser(userId: String): MatchResult {
        // 1. Redis에서 대기열 조회 (DB 조회 없음)
        val waitingUserIds = matchingCacheService.getWaitingCandidates(excludeUserId = userId)
            ?: run {
                // Cache Miss: DB에서 로딩 후 캐시 워밍
                val dbQueue = callQueueRepository.findMatchCandidatesWithProfile(userId)
                dbQueue.forEach { matchingCacheService.addToWaitingQueue(it.userId, it.waitingSince.toEpochSecond(ZoneOffset.UTC)) }
                matchingCacheService.getWaitingCandidates(excludeUserId = userId)
            } ?: return MatchResult(status = "WAITING")

        // 2. 차단 목록 캐시 조회 (DB 조회 없음)
        val blockedIds = matchingCacheService.getBlockedUsers(userId)
            ?: run {
                val dbBlocked = blockRepository.findBlockedUserIdsByUserId(userId).toSet()
                matchingCacheService.cacheBlockedUsers(userId, dbBlocked)
                dbBlocked
            }

        // 3. 최근 매칭 이력 Redis 조회
        val recentMatched = matchingCacheService.getRecentMatchedUsers(userId)

        // 4. 제외 대상 필터링 (메모리 연산, DB 없음)
        val excludeIds = blockedIds + recentMatched + userId
        val eligible = waitingUserIds.filter { it !in excludeIds }
        if (eligible.isEmpty()) return MatchResult(status = "WAITING")

        // 5. 프로필 캐시 배치 조회 (미스된 것만 DB 조회)
        val profiles = eligible.mapNotNull { candidateId ->
            matchingCacheService.getUserProfile(candidateId)
                ?: loadAndCacheProfile(candidateId)
        }

        // 6. 매칭 로직 (메모리 연산)
        val matched = profiles.firstOrNull { it.isActive } ?: return MatchResult(status = "WAITING")

        // 7. 매칭 완료 처리
        matchingCacheService.removeFromWaitingQueue(matched.userId)
        matchingCacheService.removeFromWaitingQueue(userId)
        matchingCacheService.addRecentMatchedUser(userId, matched.userId)
        matchingCacheService.addRecentMatchedUser(matched.userId, userId)

        return MatchResult(status = "MATCHED", matchedUserId = matched.userId)
    }

    // 캐시 미스 시 단건 DB 조회 + 캐시 저장
    private fun loadAndCacheProfile(userId: String): UserMatchProfileDto? {
        val profile = userProfileRepository.findMatchInfoByUserId(userId) ?: return null
        matchingCacheService.cacheUserProfile(userId, profile)
        return profile
    }
}
